// HandleQRCode .
// @router /api/qrcode [GET]
func HandleQRCode(ctx context.Context, c *app.RequestContext) {
	var err error
	var req index.GetQRCodeRequest
	err = c.BindAndValidate(&req)
	if err != nil {
		c.String(consts.StatusBadRequest, err.Error())
		return
	}

	rawURL := c.DefaultQuery("url", "")
	if rawURL == "" {
		c.String(consts.StatusBadRequest, "missing url parameter")
		return
	}

	parsed, err := url.Parse(rawURL)
	if err != nil || (parsed.Scheme != "http" && parsed.Scheme != "https") {
		c.String(consts.StatusBadRequest, "invalid url")
		return
	}

	png, err := qrcode.Encode(rawURL, qrcode.Medium, 256)
	if err != nil {
		logger.Error("QR code generation error: %v", err)
		c.String(consts.StatusInternalServerError, "failed to generate QR code")
		return
	}

	c.Header("Content-Type", "image/png")
	c.SetStatusCode(consts.StatusOK)
	c.Response.BodyWriter().Write(png)
}

// treeToCompleteMap 将 TreeNode 转换为完整的树结构 map（包含 children）
func treeToCompleteMap(node *model.TreeNode) map[string]interface{} {
	if node == nil {
		return map[string]interface{}{
			"name": "/",
			"path": "/",
		}
	}
	result := map[string]interface{}{
		"name":  node.Name,
		"path":  node.Path,
		"isDir": node.IsDir,
	}
	// 转换 children
	if len(node.Children) > 0 {
		children := make([]map[string]interface{}, 0, len(node.Children))
		for _, child := range node.Children {
			children = append(children, treeToCompleteMap(child))
		}
		result["children"] = children
	}
	return result
}
